patterns.codeBlock:
// Wrong - infinite recursion
function process(data) {
  return process(data); // no base case!
}

// Correct - add base case
function process(data) {
  if (data.length === 0) return []; // base case
  return [data[0], ...process(data.slice(1))];
}

// Better - use iteration for large data
function process(data) {
  const result = [];
  for (const item of data) {
    result.push(item);
  }
  return result;
}

